using NP std;
NP ak
{
	il int read()
	{
		int x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(int x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(int x)
	{
		write(x);
		pc('\n');
	}
	void writespace(int x)
	{
		write(x);
		pc(' ');
	}
}
using NP ak;
struct node
{
	int x, y;
};
queue<node> q;
int ans[1100][1100], death[1100][1100];
int dx[4] = {0, 1, -1, 0};
int dy[4] = {1, 0, 0, -1};
int m, s = 1000000;
void bfs()
{
	q.push({0, 0});
	ans[0][0] = 0;
	while (!q.empty())
	{
		node t = q.front();
		int tx = t.x, ty = t.y;
		q.pop();
		for (int i = 0; i < 4; i ++)
		{
			int x = tx + dx[i];
			int y = ty + dy[i];
			if (x < 0 || y < 0 || x > 1000 || y > 1000 || ans[x][y] != -1 || ans[tx][ty] + 1 >= death[x][y])
			{
				continue;
			}
			ans[x][y] = ans[tx][ty] + 1;
			q.push({x, y});
		}
	}
	return;
}
signed main(void)
{

	memset(ans, -1, sizeof(ans));
	memset(death, 0x7f, sizeof(death));
	cin >> m;
	while (m --)
	{
		int x, y, t;
		cin >> x >> y >> t;
		death[x][y] = min(death[x][y], t);
		for (int i = 0; i < 4; i ++)
		{
			int nx = x + dx[i];
			int ny = y + dy[i];
			if (nx >= 0 && ny >= 0) death[nx][ny] = min(death[nx][ny], t);
		}
	}
	bfs();
	if (death[0][0] > 1000)
	{
		cout << 0;
		return 0;
	}
	for (int i = 0; i <= 1005; i ++)
	{
		for (int j = 0; j <= 1005; j ++)
		{
			if (death[i][j] > 1000 && ans[i][j] != -1)
			{
				s = min(s, ans[i][j]);
			}
		}
	}
	if (s == 1000000)
	{
		cout << -1;
	}
	else
	{
		cout << s;
	}
	return false;
}
